function lsRelatedHTML(sid){var m=LS_META[sid];if(!m)return '';
  if(!m.related||!m.related.length)return '';
  var rows=m.related.map(function(rid,i){
    var rs=LS_META[rid]?LS_META[rid].short:rid;
    var g=m.relatedGlyph[i];
    return '<button class="ls-related-tile" type="button" data-section="'+rid+'">'+
      '<span class="ls-related-tile-ic"><svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.6" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true">'+g+'</svg></span>'+
      '<span class="ls-related-tile-label">'+rs+'</span>'+
    '</button>';
  }).join('');
  return '<div class="ls-related"><div class="ls-related-h">More in '+m.deptName+'</div><div class="ls-related-row">'+rows+'</div></div>';
}
function lsFrame(sid, inner){var m=LS_META[sid];
  if(!m)return inner;
  return '<div class="ls-frame">'+
    '<div class="ls-bar"></div>'+
    '<div class="ls-h"><h2>'+m.short+'</h2><span class="ls-dept">'+m.deptName+'</span></div>'+
    (m.lead?'<p class="ls-lead">'+m.lead+'</p>':'')+
    '<div class="ls-panel">'+inner+'</div>'+
    lsRelatedHTML(sid)+
  '</div>';
}
function lsApplyDeptClass(sid){var m=LS_META[sid];if(!m)return;
  var b=document.body;
  Object.keys({lobby:1,story:1,prod:1,voice:1,ai:1,look:1,distro:1,dev:1}).forEach(function(c){b.classList.remove('ls-cat-'+c);});
  b.classList.add('ls-cat-'+m.dept);
}

const KEY='loadstudio_complete_state_v1';
let state=JSON.parse(localStorage.getItem(KEY)||'null')||structuredClone(window.LOAD_STUDIO_INITIAL);
let featureData=window.LOAD_STUDIO_FEATURES;
let currentScene=0;
const $=s=>document.querySelector(s); const $$=s=>[...document.querySelectorAll(s)];
const esc=s=>String(s??'').replace(/[&<>\"]/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;'}[c]));
function save(){localStorage.setItem(KEY,JSON.stringify(state));render();}
function uid(prefix){return prefix+'-'+Date.now().toString(36)+'-'+Math.random().toString(36).slice(2,5)}
function log(msg){state.logs=state.logs||[];state.logs.push(new Date().toLocaleTimeString()+' - '+msg);localStorage.setItem(KEY,JSON.stringify(state));}
function modal(title,body){$('#modalTitle').textContent=title;$('#modalBody').innerHTML=body;$('#modal').classList.add('show')}
function closeModal(){$('#modal').classList.remove('show')}
function download(name,text,type='application/json'){const b=new Blob([text],{type});const a=document.createElement('a');a.href=URL.createObjectURL(b);a.download=name;a.click();setTimeout(()=>URL.revokeObjectURL(a.href),1000)}
function go(id){lsApplyDeptClass(id);$$('.section').forEach(s=>s.classList.remove('active')); const el=$('#section-'+id); if(el){el.classList.add('active'); el.scrollIntoView({behavior:'smooth',block:'start'});} }
function sectionById(id){return featureData.sections.find(s=>s.id===id)}
function statusText(section){if(section.type==='integration')return 'Integration Required: this tool needs API keys, backend, microphone permission, FFmpeg, cloud storage, Load Play endpoint, or live provider access.'; if(section.type==='mixed')return 'Local workflow is implemented. Live provider or backend actions are marked Integration Required where needed.'; return 'Local workflow implemented in this PWA.'}
// Wrapped in a function so `${id}` resolves to the section id at
